import{_ as i,o as t,c as a,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"97. Amenities","description":"","frontmatter":{"title":"97. Amenities","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["allowances","clinical-supervision","ohs","classifications"]},"headers":[],"relativePath":"ebas/mspp/clinical-supervision/97-amenities.md","filePath":"ebas/mspp/clinical-supervision/97-amenities.md"}'),n={name:"ebas/mspp/clinical-supervision/97-amenities.md"};function o(r,e,l,c,p,h){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="_97-amenities" tabindex="-1">97. Amenities <a class="header-anchor" href="#_97-amenities" aria-label="Permalink to &quot;97. Amenities&quot;">​</a></h1><p><strong>a.</strong> A Psychologist will, as far as reasonably practicable, have access to:</p><p><strong>(i)</strong> an office space,</p><p><strong>(ii)</strong> technology, including a computer and/or laptop, telephone and mobile phone and storage facilities, and</p><p><strong>(iii)</strong> clinical spaces to see patients, that is appropriate having regard to the work performed by the Psychologist, including the need for privacy in clinical and professional activities (including clinical supervision and leadership responsibilities).</p><p><strong>b.</strong> Having regard to the clinical duties performed by a Psychologist, and as far as reasonably practicable, a Psychologist will not be required to share clinical spaces or hot desk for the purpose of performing clinical duties. In the event that a Psychologist is required to share a clinical space or hot desk for the purpose of performing clinical duties, the Employer will, as far as reasonably practicable, give consideration to alternatives, such as remote working locations (including work from home) or appropriate on-site breakout space. Agreement to alternative arrangements will not be unreasonably refused.</p><p><strong>c.</strong> Where a Psychologist performs work from home and/or undertake consultations using Telehealth, the Psychologist will be provided with appropriate equipment (including mobile phones and computers) and secure communications software.</p><p><strong>d.</strong> Where the Employer is considering construction or refurbishment of facilities a Psychologist uses, the Employer will consider the items outlined in sub-clause 97a and consult in accordance with <a href="/eba/ebas/mspp/employment/30-consultation.html">clause 30</a> of the Agreement.</p><p><strong>e.</strong> In the event that items identified in 97a and 97b are unable to be provided, the Psychologist will immediately raise concerns with their supervisor and/or manager who will work to resolve the concerns in the event that the concerns</p><p>cannot be immediately resolved, the Employer will develop strategies to mitigate concerns.</p><p><strong>f.</strong> Where a Psychologist has concerns regarding the safety of clinical spaces, the Psychologist will raise any concerns and the Employer will respond in accordance with existing internal Occupational Health and Safety processes.</p><p><strong>g.</strong> Nothing in this clause prevents a Government directive related to occupational health and safety or items in this clause from taking precedence.</p><p>Plain language terms: staff amenities, facilities.</p>',13)])])}const g=i(n,[["render",o]]);export{m as __pageData,g as default};
